INSERT INTO regular_expressions (name, pattern, description) VALUES ('3D', '(?<=\b[12]\d{3}\b).*\b((bluray|bd)?3d|sbs|half[ .-]ou|half[ .-]sbs)\b', 'Marqueurs 3D (bluray3d, SBS, half-OU) après l’année. Malus fréquent : peu d’installations 3D actives.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('AAC', '\bAAC(\b|\d)', 'Codec AAC dans le titre (AAC, AAC5.1). Audio lossy courant en WEB ; distinct de Dolby et DTS.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('AV1', '\b(AV1)\b', 'Codec AV1 dans le titre. Exclu sur les profils FR (score -999999) pour compatibilité lecteurs.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Basic HDR Formats', '(?:(?<=^(?!.*\b(HLG|PQ|SDR)(\b|\d)).*?)HDR)|\b(dv(?![ .](HLG|SDR))|dovi|dolby[ .]?vision)\b', 'Mention HDR ou DV / Dolby Vision, hors combinaisons HLG, PQ ou SDR trompeuses.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS Basic', 'DTS[ .]?[1-9]', 'DTS suivi d’un chiffre de canaux (ex. DTS.5, DTS 5). Variante télégraphique ancienne.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-ES', '(?i)dts[-. ]?es\b', 'DTS-ES (Extended Surround), extension matricielle 6.1 sur vieux DVD/Bluray.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-HD HRA ES', 'dts[-. ]?(es|(hd[. ]?)?(hr|hi))', 'Variantes DTS-ES et DTS high resolution (HR, HI) pour éviter les doublons audio.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-HD HRA', '(?i)dts[-. ]?(hd[. ]?)?(hra?|hi\b)', 'DTS-HD High Resolution (HRA). Couche intermédiaire entre DTS core et DTS-HD MA.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-HD MA', '(?i)\b(dts[-_. ]?(ma|hd([-_. ]?ma)?|xll))(\b|\d)', 'DTS-HD Master Audio (MA, XLL). Lossless fréquent sur Blu-ray, UHD et WEB premium.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-X', '(?i)\b(dts[-_. :]?x)\b(?!\d)', 'DTS:X (audio objet). Distinct de DTS-HD MA et du DTS classique.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS', '\bDTS(\b|\d)', 'DTS core (hors HD ou X), souvent avec suffixe de canaux (DTS5, DTS.5).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Digital +', '(?i)\b(?:DD[P+]|eac3(?:\b|[_. ]\d)|e[-_. ]?ac[-_. ]?3(?:\b|[_. ]\d))\b', 'Dolby Digital Plus (DD+, E-AC-3, EAC3.5.1 Torr9/C411). Distinct du Dolby Digital classique.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Digital', '(?i)\b(?:DD(?![a-z+])|(?<!e-)(?<!e\.)(?<!e_)(?<!e )(?<!e)ac[-_. ]?3(?:\b|[_. ]\d))\b', 'Dolby Digital classique (DD, AC-3, AC3.5.1 Torr9/C411). Exclut E-AC-3/EAC3 (DD+).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Vision (Without Fallback)', '(?<=^(?!.*(HDR|HULU|REMUX|BLURAY)).*?)\b(DV|Dovi|Dolby[- .]?V(ision)?)\b', 'Dolby Vision sans HDR10 lisible dans le titre. Malus compatibilité lecteurs anciens.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Vision', '(?i)\b(dv(?![ .](HLG|SDR))|dovi|dolby[ .]?vision)\b', 'Alias DV, DoVi, Dolby Vision. Exclut DV accolé à HLG ou SDR seuls.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FLAC', '\bFLAC(\b|\d)', 'Piste FLAC annoncée dans le titre. Distinct du PCM/LPCM.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-4KLight', '(?i)\b4K[ ._-]?Light\b', 'Tag 4KLight (Bluray UHD allégé). Référence scène FR (QTZ, BONBON).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Atmos-Bundle', '(?i)(?:\bATMOS\b|DDPA(\b|\d)|\bTrue[ .-]?HDA[ .-]?[57]\.1)', 'Atmos, DDPA et variante TrueHD.A 5.1/7.1 (BTN) en un seul motif.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Blockers', '(?i)\b(k0RE|Wawacity|YIFY|YTS|RARBG|FGT|GalaxyRG|GalaxyTV|MeGusta|ETRG|ION10|TGx|WAVES|NoGRP|NoGroup|ATTKC|SUJAIDR|LAMA|TimeStrike|Pahe|TBS|EVO|RMTeam|ETHEL|Telly|playSD|playWEB)\b|\b(NVENC|QSV|AMF)\b|(?=.*\b(REMUX|BDMV|ISO)\b)(?=.*\b(x26[45]|h26[45])\b)', 'Groupes bannis, encodeurs GPU (NVENC, QSV, AMF) et incohérences REMUX+encodeur.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-HDLight', '(?i)\bHDLight\b', 'Tag HDLight (Bluray allégé). Courant en 1080p/720p sur trackers FR.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Hybrid', '(?i)\bHYBRID\b', 'Tag HYBRID (Bluray hybride multi-sources). Bonus UHD sur profils 4K.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-MULTI', '(?i)(?:MULTITRUEFRENCH|MULTIVFF|MULTIVF2|MULTIVFQ|MULTIVFI|MULTI[ ._-]?(?:TRUEFRENCH|VFF|VF2|VFQ|VOQ|FRENCH|VFI|VOF|VFB)|MULTI[ ._-]?FRENCH)|\bMULTI\b', 'Tag MULTI : MULTI.VFF, MULTIVFF collé (C411), MULTITRUEFRENCH, etc. Mot entier MULTI seul.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Streamers-Premium', '(?:\b(?:NF|Netflix)\b|\b(?:AMZN|(?:AMAZON)(?=\s*.(?:WEB-?DL|WEBRIP)))\b|\b(?:dsnp|dsny(?:p)?|disney\+)\s*\b|\b(?:ATVP|ATV|APTV|Apple TV\+)\s*\b|\b(?:HMAX|HBOM|(?:HBO[ ._-]?MAX)(?=\s*.(?:WEB-?DL|WEBRIP)))\b|\b(?:(?<!hbo[ ._-])max)\b(?=[ ._-]web[ ._-]?(?:dl|rip)\b)|\[(?:MAX)\b|\b(?:MAX)\]|\b(?:PMTP|Paramount Plus)\b)', 'WEB premium : Netflix, Prime, Disney+, Apple TV+, HBO Max, Paramount+.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Streamers-Standard', '(?i)(?:\bnow\b[ ._-]web[ ._-]?(?:dl|rip)?\b|\[(?:NOW)\b|\b(?:NOW)\]|\b(?:C(?:runchy)?[ .-]?R(?:oll)?)\b|\b(?:it|itunes)\b(?=[ ._-]web[ ._-]?(?:dl|rip)\b)|\[(?:iT)\b|\b(?:iT)\])', 'WEB secondaires : NOW/Sky, Crunchyroll, iTunes (tags WEB).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-VF2', '(?i)(?:MULTIVF2|MULTIVFQ|MULTI[ ._-]?VF2|MULTI[ ._-]?VFQ|MULTI[ ._-]?VOQ)|\b(VF2|VFQ|VOQ)\b', 'Tags VF2, VFQ, VOQ : MULTI.VF2, MULTIVF2 collé (C411), etc.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-VFF', '(?i)(?:MULTITRUEFRENCH|MULTIVFF|MULTIVFI|MULTI[ ._-]?TRUEFRENCH|MULTI[ ._-]?VFF|MULTI[ ._-]?FRENCH)|\b(VFF|TRUEFRENCH|VFI|VOF|VFB|VF(?!Q|2)|FRENCH|FRANCAIS|FRANÇAIS)\b', 'Tags FR hors VF2/VFQ : VFF, MULTI.VFF, MULTIVFF collé (C411), VFI, FRENCH, etc.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-VOSTFR', '(?i)\b(VOST[ ._-]?FR|SUBFRENCH|FANSUB|FASTSUB)\b', 'Sous-titres FR sur VO : VOSTFR, SUBFRENCH, FANSUB, FASTSUB.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Repack-2', '(?i)\b(?:(?:proper|repack)2\b|(?:real[\s._-]+){1,2}proper\b)', 'PROPER2, REPACK2 ou chaîne REAL puis PROPER (hors niveau 3).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Repack-3', '(?i)\b(?:proper|repack)3\b', 'PROPER3 ou REPACK3 — correction la plus aboutie.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Repack', '(?i)\b(?!(?:proper|repack)[23]\b|(?:real[\s._-]+){1,2}proper\b)(?:real[\s._-]+){0,2}(?:repack|rerip|proper)[123]?\b', 'PROPER, REPACK, RERIP ou REAL simple (hors niveaux 2 et 3).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Tier-01', '(?i)\b(BOUBA|NEOSTARK|N3ZUKO|J4CK|MAXADONF|Maxadonf|D4RK|R3MiX|RAPTOR|Themouche|SUPERFLU|LaFistiniere|R3DUCT0|SHADOW|Shadow|OPTIMUM|ESPER|D5T0)\b', 'Encodeurs palier 01 (BOUBA, NEOSTARK, etc.). Sous les équipes FR-Team.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Tier-02', '(?i)\b(TLC|DN55|Dramas[ ._]?For[ ._]?Ever|DFE|KAF|NYX|raf66|Raf66|HazzAnim|prem|FIST|Fist|Macolive|GISMO65|ZEKEY|FIRESOUL64|Firesoul64|PokemonFansub|FANKAI|PiCKLES|KPORAL|ACKER|TG7|STORiES|RiFiFi|DRIVE|AuriA|STIF|FUTE69|higgsboson|Alicia|BOONA33|RedROses|jdjo69|Luju|hyhyho|Chachou6768|TTK|Kaoru111|PARISTOCAT|tlub|ztgold|UKDHD|ZatNik07|Dixcents|Sicario|XSHD|DELIRIUS)\b', 'Encodeurs palier 02 (TLC, DFE, KPORAL, DELIRIUS, etc.). Sous FR-Tier-01.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Full Disc', '(?i)^(?!.*\b((?<!HD[._ -]|HD)DVD|BDRip|MKV|XviD|WMV|d3g|BDREMUX|REMUX|^(?=.*1080p)(?=.*HEVC)|[xh][-_. ]?26[45]|German.*DL|((?<=\d{4}).*German.*(DL)?)(?=.*\b(AVC|HEVC|VC[-_. ]?1|MVC|MPEG[-_. ]?2)\b))\b)(((?=.*\b(Blu[-_. ]?ray|BD|HD[-_. ]?DVD)\b)(?=.*\b(AVC|HEVC|VC[-_. ]?1|MVC|MPEG[-_. ]?2|BDMV|ISO)\b))|^((?=.*\b(^((?=.*\b((.*_)?COMPLETE.*|Dis[ck])\b)(?=.*(Blu[-_. ]?ray|HD[-_. ]?DVD)))|3D[-_. ]?BD|BR[-_. ]?DISK|Full[-_. ]?Blu[-_. ]?ray|^((?=.*((BD|UHD)[-_. ]?(25|50|66|100|ISO)))))))).*|(?:DVD9|DVD5|NTSC|PAL|VOB IFO|VC-1|AVC|MPEG-2|\bCOMPLETE[-.\s]?(?:UHD[-.\s])?BLU[-.\s]?RAY\b|\bCOMPLETE BLURAY\b|\bBR-Disk\b)', 'Image disque complète (ISO, BDMV, BR-DISK). Motif strict pour limiter les faux positifs.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HDR', '\b(HDR)\b', 'Mention HDR générique. Affinée ensuite par HDR10, HDR10+ et exclusions SDR.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HDR10+', '\bHDR10.?(\+|P(lus)?\b)', 'HDR10+ (HDR10 PLUS). Suffixe + ou Plus après HDR10.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HDR10', '\bHDR10(?!\+|Plus)\b', 'HDR10 strict, sans suffixe Plus réservé à HDR10+.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HLG', '\b(HLG)\b', 'HLG (Hybrid Log-Gamma), HDR broadcast télé.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('IMAX Enhanced', '(?i)^(?=.*\b((DSNP|Disney\+|BC|B?CORE)(?=.?web.?(dl|rip)\b)))(?=.*\b((?<!NON.?)IMAX(.?Enhanced)?)\b)', 'IMAX Enhanced sur WEB Disney+ ou Bravia Core, hors NON-IMAX.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('IMAX', '\b((?<!NON.?)IMAX)\b', 'Mention IMAX (hors NON-IMAX). Distinct du CF IMAX Enhanced.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Opus', '\bOPUS(\b|\d)(?!.*[ ._-](\d{3,4}p))', 'Codec Opus dans le titre. Ignore les fausses alertes type résolution 1080p après OPUS.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('PCM', '(?i)\b(l?)PCM(\b|\d)', 'PCM ou LPCM non compressé dans le titre.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('PQ', '\b(PQ|PQ10)\b', 'PQ ou PQ10 (Perceptual Quantizer), métadonnées HDR10.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Remux', '(?i)Remux', 'Mot Remux dans le titre. Conteneur sans ré-encodage depuis Blu-ray/UHD.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('SDR', '\b(SDR)\b', 'Mention SDR explicite (gamme standard, pas HDR).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Theatrical Edition', '(?i)^(.*?)(\d{4})(.*?)\b(theatrical)\b', 'Theatrical après l’année (4 chiffres) pour éviter les faux positifs.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TrueHD', 'True[ .-]?HD[ .-]?', 'Dolby TrueHD dans le titre. Atmos géré par FR-Regex-Atmos-Bundle.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('UHD Bluray', '\bUHD[-_.\s]?Blu[-]?Ray\b', 'Source UHD Blu-ray annoncée (variantes d’écriture UHD Bluray).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Upscaled', '(Up[-\.\s]?scale|Re[-\.\s]?Grade|\bAIUS\b|AI[-\.\s]?enhanced)', 'Upscale, regrade ou tags type AI enhanced / AIUS.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('VP9', '\b(VP9)\b', 'Codec VP9 dans le titre.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('VVC', '(?<=^|[\s.-])VVC\b', 'VVC / H.266 (codec rare, bonus expérimental si décodage HW).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Xvid', '(?i)[-. ]Xvid', 'Ancien codec Xvid (MPEG-4 ASP), surtout SD legacy.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('h265', '(?i)(?:\b[hH][\s.-]?265\b|\bHEVC\b)', 'Mention H.265 / H265 / HEVC (C411 Slay3R, etc.).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('AMEN', '(?i)(?<=^|[\s.-])AMEN\b', 'Groupe AMEN — WEB 2160p compact. Lié au CF FR-Team-AMEN.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('BONBON', '(?i)(?<=^|[\s.-])BONBON\b', 'Groupe BONBON — 4KLight / WEBRip compact. Lié au CF FR-Team-BONBON.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('BOUC', '(?i)(?<=^|[\s.-])BOUC\b', 'Groupe BOUC — WEB 2160p premium. Lié au CF FR-Team-BOUC.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('ENIGMA', '(?i)(?<=^|[\s.-])ENIGMA\b', 'Groupe ENIGMA — WEB 1080p/2160p, MULTI VF. Lié au CF FR-Team-ENIGMA.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FW', '(?i)(?<=^|[\s.-])(?:FORWARD|FW)\b', 'Groupe Forward (FW / FORWARD). Lié au CF FR-Team-FW.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HYPERION', '(?i)(?<=^|[\s.-])HYPERION\b', 'Groupe HYPERION — surtout Remux UHD. Lié au CF FR-Team-HYPERION.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('OZEF', '(?i)(?<=^|[\s.-])OZEF\b', 'Groupe OZEF — Remux Blu-ray/UHD. Lié au CF FR-Team-OZEF.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('PopHD', '(?i)(?<=^|[\s.-])PopHD\b', 'Groupe PopHD — 1080p HDLight x264. Lié au CF FR-Team-PopHD.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('QTZ', '(?i)(?<=^|[\s.-])QTZ\b', 'Groupe QTZ — référence 4KLight. Lié au CF FR-Team-QTZ.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('SUPPLY', '(?i)(?<=^|[\s.-])SUPPLY\b', 'Groupe SUPPLY — WEB 2160p premium. Lié au CF FR-Team-SUPPLY.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Slay3R', '(?i)(?<=^|[\s.-])Slay3R\b', 'Groupe Slay3R — WEB 1080p/2160p/720p C411 (H264/H265). Lié au CF FR-Team-Slay3R.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TFA', '(?i)(?<=^|[\s.-])TFA\b', 'Groupe TFA — WEB 2160p MULTI. Lié au CF FR-Team-TFA.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('THESYNDiCATE', '(?i)(?<=^|[\s.-])THESYNDiCATE\b', 'Groupe THESYNDiCATE — WEB 2160p HEVC. Lié au CF FR-Team-THESYNDiCATE.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TOXIC', '(?i)(?<=^|[\s.-])TOXIC\b', 'Groupe TOXIC — 1080p HDLight. Lié au CF FR-Team-TOXIC.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TyHD', '(?i)(?<=^|[\s.-])TyHD\b', 'Groupe TyHD — WEB 2160p HEVC compact. Lié au CF FR-Team-TyHD.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Winks', '(?i)(?<=^|[\s.-])Winks\b', 'Groupe Winks — 1080p BluRay/WEB x265 MULTI (C411). Lié au CF FR-Team-Winks.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('x264', '^(?!.*(?i:remux)).*(?:[xh][\s.-]?264\b|\bAVC\b|DVDRip)', 'x264, H264, AVC ou DVDRip (C411 Slay3R), hors Remux.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('x265', '^(?!.*(?i:remux))(?=.*(?:[xh][\s.-]?265\b|HEVC|\bDS4K\b)).*$', 'x265, H265, HEVC ou DS4K (C411 Slay3R), hors Remux.');
